mapper.update:
update t_scm_pallet
set useyn = 'N',
ymdhms_d = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'),
memo_d = #{memo}
where bbarcode = #{barcode}
and useyn = 'Y'

mapper.select:
select NVL(SUM(qty), 0) from t_scm_pallet
where pbarcode = #{pbarcode}
and useyn = 'Y'

select NVL(lastqty, 0) from t_scm_barcode
where barcode = #{barcode}
and useyn = 'Y'

mapper.update:
update t_wms_location set qty = #{pqty}
where barcode = #{pbarcode}
and useyn = 'Y'

update t_wms_worklocation set qty = #{pqty}
where barcode = #{pbarcode}
and useyn = 'Y'
